function renderMonitor(){const r=state.recovery||{};const summary=r.summary||{};document.getElementById('monitorState').textContent=r.overallState||'—';let html='<div class="grid metrics"><div class="metric"><span>Overall</span><strong>'+esc(r.overallState||'unknown')+'</strong></div><div class="metric"><span>Blocked</span><strong>'+esc(summary.blocked||0)+'</strong></div><div class="metric"><span>Degraded</span><strong>'+esc(summary.degraded||0)+'</strong></div><div class="metric"><span>Fallback</span><strong>'+esc(r.fallbackRequired?'yes':'no')+'</strong></div></div>';html+='<div class="grid layout2"><div class="panel"><div class="panelHead"><div><h2>助手能力监控</h2><p>识别本地可恢复问题、插件授权问题与平台侧拦截。</p></div>'+badge(r.overallState||'unknown')+'</div><div class="panelBody">'+((r.capabilities||[]).map(function(c){return '<div class="notice"><strong>'+esc(c.label||c.id)+'</strong><p>'+badge(c.state||'unknown')+' '+esc(c.class||'unknown')+' · '+esc(c.reason||'')+'</p></div>'}).join('')||'<div class="empty">暂无监控数据</div>')+'</div></div><div class="panel"><div class="panelHead"><div><h2>推荐恢复动作</h2><p>只读动作可直接执行，写动作需要显式授权并写入 audit。</p></div></div><div class="panelBody">'+((r.recommendedActions||[]).map(function(a){return '<div class="notice"><strong>'+esc(a.title||a.id)+'</strong><p>'+esc(a.risk)+' · '+esc(a.confirmation)+' · '+esc(a.description||'')+'</p>'+recoveryActionButton(a)+'</div>'}).join('')||'<div class="empty">当前无推荐恢复动作</div>')+'</div></div></div>';if((r.notes||[]).length)html+='<div class="panel"><div class="panelBody">'+r.notes.map(function(n){return '<div class="notice"><strong>说明</strong><p>'+esc(n)+'</p></div>'}).join('')+'</div></div>';document.getElementById('monitor').innerHTML=html}
