function openIssue(id){const i=findIssue(id);if(!i)return;const runs=(state.runs||[]).filter(function(r){return r.issueId===id});const edits=(state.editSessions||[]).filter(function(e){return e.issueId===id});const events=(state.timeline||[]).filter(function(e){return e.issueId===id}).slice(0,40);document.getElementById('dialogTitle').textContent=i.title;document.getElementById('dialogSub').textContent=i.id;document.getElementById('dialogBody').innerHTML='<h3>概览</h3><dl class="detailGrid"><dt>状态</dt><dd>'+badge(i.status)+'</dd><dt>类型</dt><dd>'+esc(i.kind)+'</dd><dt>更新时间</dt><dd>'+fmt(i.updatedAt)+'</dd></dl><h3>子 Tasks</h3>'+((i.tasks||[]).map(function(t){return taskRow(i,t)}).join('')||'<div class="empty">没有 Task</div>')+'<h3>变更</h3><p>Direct Edits '+edits.length+' · Agent Runs '+runs.length+'</p>'+edits.map(function(e){return '<div class="notice"><strong>'+esc(e.purpose)+'</strong><p>'+esc(e.sessionId)+' · '+esc(e.status)+'</p><button onclick="openEdit(\''+esc(e.sessionId)+'\')">查看</button></div>'}).join('')+'<h3>活动</h3>'+events.map(function(e){return '<div class="event"><div class="eventTop"><strong>'+esc(e.summary||e.action)+'</strong><span>'+fmt(e.at)+'</span></div><p>'+esc(e.category)+'</p></div>'}).join('');dialog.showModal()}
function openTask(i,t){const task=findTask(i,t);if(!task)return;const runs=(state.runs||[]).filter(function(r){return r.issueId===i&&r.taskId===t});document.getElementById('dialogTitle').textContent=task.title;document.getElementById('dialogSub').textContent=i+' / '+t;document.getElementById('dialogBody').innerHTML='<dl class="detailGrid"><dt>状态</dt><dd>'+badge(task.effectiveStatus)+'</dd><dt>目标</dt><dd>'+esc(task.objective||'—')+'</dd><dt>允许路径</dt><dd>'+esc((task.allowedPaths||[]).join(', ')||'未限制')+'</dd><dt>Agent 提示</dt><dd>'+esc(task.agent||'无，运行时选择')+'</dd></dl><div class="sectionTitle"><h2>执行</h2></div><div class="actions"><select id="dialogAgent">'+agentOptions(task.agent||((state.execution.allowedAgents||[])[0]))+'</select><button class="primary" onclick="launchTaskFromDialog(\''+esc(i)+'\',\''+esc(t)+'\')">使用 Agent</button><button onclick="verifyTask(\''+esc(i)+'\',\''+esc(t)+'\')">验证</button><button onclick="acceptTask(\''+esc(i)+'\',\''+esc(t)+'\')">完成</button></div><h3>执行记录</h3>'+((runs.map(function(r){return '<div class="notice"><strong>'+esc(r.runId)+'</strong><p>'+esc(r.agent)+' · '+esc(r.status)+'</p><button onclick="openRun(\''+esc(r.runId)+'\')">查看</button></div>'}).join(''))||'<div class="empty">暂无 Run</div>');dialog.showModal()}
