var state=null;var safeMode=false;var activeView='dashboard';var openRunId=null;var runRefreshTimer=null;var activityFilter='all';
var dialog=document.getElementById('dialog');
function esc(v){return String(v==null?'':v).replace(/[&<>"']/g,function(c){return({'&':'&amp;','<':'&lt;','>':'&gt;','"':'&quot;',"'":'&#39;'})[c]})}
function arr(v){return Array.isArray(v)?v:[]}
function obj(v){return v&&typeof v==='object'&&!Array.isArray(v)?v:{}}
function fmt(v){if(!v)return '—';try{return new Date(v).toLocaleString()}catch(_e){return String(v)}}
function short(v,n){v=String(v==null?'':v);n=n||96;return v.length>n?v.slice(0,n-1)+'…':v}
function statusClass(v){v=String(v||'').toLowerCase();if(/ready|healthy|success|succeeded|pass|verified|accepted|enabled|clean|fresh/.test(v))return 'green';if(/fail|error|blocked|denied|expired|unavailable|destructive|mismatch|dirty|cancelled|timeout/.test(v))return 'red';if(/waiting|pending|review|degraded|warning|queued|running|planned|ready_for|attention|auth/.test(v))return 'amber';if(/run|active|starting|dispatch|progress/.test(v))return 'brand';return 'gray'}
function badge(v,label){return '<span class="badge '+statusClass(v)+'">'+esc(label||v||'unknown')+'</span>'}
function metric(label,value,sub,kind){return '<div class="metric"><span>'+esc(label)+'</span><strong class="'+(kind||'')+'">'+esc(value)+'</strong>'+(sub?'<small>'+esc(sub)+'</small>':'')+'</div>'}
function api(path,opts){opts=opts||{};var headers=Object.assign({'content-type':'application/json'},opts.headers||{});return fetch(path,Object.assign({},opts,{credentials:'same-origin',headers:headers})).then(function(r){return r.json().catch(function(){return{}}).then(function(body){if(!r.ok)throw new Error(body.error||body.message||String(r.status));return body})})}
function toastMsg(msg){var t=document.getElementById('toast');t.textContent=msg;t.classList.add('show');setTimeout(function(){t.classList.remove('show')},4200)}
function toggleSafeMode(){safeMode=!safeMode;document.getElementById('appShell').classList.toggle('safeMode',safeMode);document.getElementById('safeModeBtn').textContent=safeMode?'解除写暂停':'暂停写动作';toastMsg(safeMode?'已暂停 UI 写动作。':'已解除 UI 写动作暂停。')}
function requireWrite(){if(safeMode){toastMsg('写动作已暂停，请先解除顶部 Safe Mode。');return false}return true}
function focusCommand(){document.getElementById('commandInput').focus()}
function handleCommandKey(e){if(e.key==='Enter')submitIntent()}
function switchView(name){activeView=name;document.querySelectorAll('.nav button').forEach(function(b){b.classList.toggle('active',b.dataset.view===name)});document.querySelectorAll('.view').forEach(function(v){v.classList.toggle('active',v.id==='view-'+name)});renderAll()}
document.querySelectorAll('.nav button').forEach(function(b){b.addEventListener('click',function(){switchView(b.dataset.view)})});
window.addEventListener('keydown',function(e){if((e.metaKey||e.ctrlKey)&&e.key.toLowerCase()==='k'){e.preventDefault();focusCommand()}});
function submitIntent(){if(!requireWrite())return;var input=document.getElementById('commandInput');var utterance=input.value.trim();if(!utterance)return;api('/api/assistant/intent',{method:'POST',body:JSON.stringify({utterance:utterance,source:'local-ui',mode:'execute'})}).then(function(result){input.value='';toastMsg('任务已提交：'+(result.requestId||result.jobId||'accepted'));refresh();switchView('tasks')}).catch(function(e){toastMsg(e.message)})}
function activeIssues(){return arr(obj(state&&state.board).issues).filter(function(i){return !['done','archived','cancelled','superseded'].includes(String(i.status||''))})}
function allTasks(){return activeIssues().flatMap(function(issue){return arr(issue.tasks).map(function(task){return Object.assign({issueId:issue.id,issueTitle:issue.title},task)})})}
function decisionQueues(){return obj(state&&state.decisionQueues)}
function recovery(){return obj(state&&state.recovery)}
function plugins(){return arr(state&&state.assistantPlugins)}
function routines(){return arr(obj(state&&state.assistant).routines)}
function inbox(){return arr(obj(state&&state.assistant).inbox)}
function runningItems(){var q=decisionQueues();return arr(q.runningNow)}
function approvalItems(){var q=decisionQueues();return arr(q.pendingApprovals).concat(arr(q.readyForReview)).concat(arr(q.needsAttention).filter(function(x){return String(x.status||'').includes('waiting')||String(x.status||'').includes('failed')}))}
function renderAll(){if(!state)return;updateChrome();renderDashboard();renderApprovals();renderWorkbench();renderTasks();renderMonitor();renderPlugins();renderAutomations();renderEvidence();renderDrawer()}
function updateChrome(){var q=decisionQueues();var r=recovery();var running=arr(q.runningNow).length;var approvals=approvalItems().length;var readyPlugins=plugins().filter(function(p){return p.enabled!==false&&obj(p.health).ready!==false&&obj(p.health).state!=='error'}).length;document.getElementById('topRunning').textContent=running;document.getElementById('topApprovals').textContent=approvals;document.getElementById('topPlugins').textContent=readyPlugins+'/'+plugins().length;document.getElementById('navApprovalBadge').textContent=approvals;document.getElementById('navTaskBadge').textContent=running;document.getElementById('navPluginBadge').textContent=readyPlugins+'/'+plugins().length;document.getElementById('navRoutineBadge').textContent=routines().filter(function(x){return x.enabled!==false&&x.status!=='paused'}).length;document.getElementById('navMonitorBadge').textContent=r.overallState||'—';document.getElementById('navDashboardBadge').textContent=(arr(q.needsAttention).length||'OK');document.getElementById('navRepoBadge').textContent=(obj(state.runtime).registered?'1':'—');document.getElementById('daemonState').textContent=obj(obj(state.runtime).daemon).status||'LOCAL';document.getElementById('sideRepo').textContent=short(state.repoRoot||'—',28)}
function renderDashboard(){var q=decisionQueues();var r=recovery();var issueCount=activeIssues().length;var taskCount=allTasks().filter(function(t){return !['done','cancelled','superseded'].includes(String(t.effectiveStatus||''))}).length;var readyPlugins=plugins().filter(function(p){return p.enabled!==false&&obj(p.health).ready!==false&&obj(p.health).state!=='error'}).length;var html='<div class="pageHead"><div><h1>今日状态大盘</h1><p>把任务队列、审批阻塞、仓库健康、插件授权和平台拦截放在同一个可操作视图。</p></div><div class="toolbar"><button onclick="switchView(\'monitor\')">助手监控</button><button onclick="refresh()">刷新</button></div></div>';html+='<div class="grid metrics">'+metric('安全拦截 / 待处理',approvalItems().length,'Approval Inbox','')+metric('并发执行中',arr(q.runningNow).length,'Running queue','')+metric('活跃 Issue / Task',issueCount+' / '+taskCount,'当前工作范围','')+metric('插件健康度',readyPlugins+' / '+plugins().length,'能力与授权','')+metric('自恢复状态',r.overallState||'unknown',r.fallbackRequired?'需要 fallback':'本地能力矩阵','')+'</div>';html+='<div class="grid layout2"><div class="panel"><div class="panelHead"><div><h2>当前任务队列</h2><p>优先展示正在执行、等待用户、失败或等待审查的工作。</p></div><span class="badge brand">'+arr(q.runningNow).length+' running</span></div><div class="panelBody">'+renderQueue(arr(q.runningNow).concat(arr(q.readyForReview)).slice(0,8),'当前没有运行中的任务')+'</div></div>';html+='<div class="panel"><div class="panelHead"><div><h2>今日故障 / 需要关注</h2><p>失败任务、平台拦截、授权过期会在这里集中暴露。</p></div>'+badge(r.overallState||'unknown')+'</div><div class="panelBody">'+renderAttention()+'</div></div></div>';html+='<div class="grid layout2" style="margin-top:16px"><div class="panel"><div class="panelHead"><div><h2>助手能力监控摘要</h2><p>平台侧拦截不会触发本地重启死循环，会引导到补丁交接或窄工具面。</p></div><button onclick="switchView(\'monitor\')">查看矩阵</button></div><div class="panelBody">'+renderRecoveryMini()+'</div></div><div class="panel"><div class="panelHead"><div><h2>插件与例行任务</h2><p>个人助手不仅改代码，也要管理邮件、日历、浏览器、移动端入口。</p></div><button onclick="switchView(\'plugins\')">配置</button></div><div class="panelBody">'+renderPluginMini()+'</div></div></div>';document.getElementById('view-dashboard').innerHTML=html}
function renderQueue(items,empty){items=arr(items);if(!items.length)return '<div class="empty">'+esc(empty)+'</div>';return items.map(function(item){var title=item.title||item.id||item.taskId||item.runId;var meta=[item.kind,item.status,item.issueId,item.taskId].filter(Boolean).join(' · ');return '<div class="row"><div><div class="rowTitle">'+esc(title)+'</div><div class="rowSub mono">'+esc(meta)+' · '+esc(fmt(item.updatedAt))+'</div></div><div class="actions">'+badge(item.status||item.kind)+' '+actionForItem(item)+'</div></div>'}).join('')}
function actionForItem(item){if(item.kind==='run'||item.runId)return '<button onclick="openRun(\''+esc(item.id||item.runId)+'\')">追踪</button>';if(item.kind==='task'||item.issueId&&item.taskId)return '<button onclick="openTask(\''+esc(item.issueId)+'\',\''+esc(item.taskId)+'\')">查看</button>';if(item.kind==='edit'||item.sessionId)return '<button onclick="openEdit(\''+esc(item.id||item.sessionId)+'\')">查看</button>';if(item.kind==='local-job')return '<button onclick="openLocalJob(\''+esc(item.id)+'\')">查看</button>';return '<button onclick="switchView(\'evidence\')">证据</button>'}
function renderAttention(){var items=arr(decisionQueues().needsAttention);var pluginProblems=plugins().filter(function(p){return obj(p.health).ready===false||obj(p.health).state==='error'||obj(p.lifecycle).state==='error'}).map(function(p){return {kind:'plugin',id:p.pluginId,title:p.displayName||p.pluginId,status:obj(p.health).state||obj(p.lifecycle).state,updatedAt:obj(p.health).checkedAt}});var all=items.concat(pluginProblems).slice(0,8);if(!all.length)return '<div class="notice green"><strong>没有明显阻塞</strong><p>当前没有失败 Run、等待人工处理的 Job 或错误插件。</p></div>';return all.map(function(x){return '<div class="notice '+(statusClass(x.status)==='red'?'red':'amber')+'"><strong>'+esc(x.title||x.id)+'</strong><p>'+esc(x.kind)+' · '+esc(x.status)+' · '+esc(fmt(x.updatedAt))+'</p></div>'}).join('')}
function renderRecoveryMini(){var r=recovery();var caps=arr(r.capabilities);var summary=obj(r.summary);var rows=[['Blocked',summary.blocked||caps.filter(function(c){return c.state==='blocked'||c.state==='unavailable'}).length],['Degraded',summary.degraded||caps.filter(function(c){return c.state==='degraded'}).length],['Fallback',r.fallbackRequired?'需要':'不需要'],['Next',short(obj(summary.nextBestAction).title||'无',48)]];return '<dl class="detailGrid">'+rows.map(function(x){return '<dt>'+esc(x[0])+'</dt><dd>'+esc(x[1])+'</dd>'}).join('')+'</dl>'+(arr(r.notes)[0]?'<div class="notice brand" style="margin-top:12px"><strong>系统判断</strong><p>'+esc(arr(r.notes)[0])+'</p></div>':'')}
function renderPluginMini(){var list=plugins().slice(0,5);if(!list.length)return '<div class="empty">暂无插件</div>';return list.map(function(p){return '<div class="split" style="margin-bottom:9px"><div><strong>'+esc(p.displayName||p.pluginId)+'</strong><div class="rowSub">'+esc(p.provider||'provider')+'</div></div>'+badge(obj(p.health).state||obj(p.lifecycle).state||'unknown')+'</div>'}).join('')}
function renderApprovals(){var items=approvalItems();var html='<div class="pageHead"><div><h1>Approval Inbox</h1><p>所有可能产生副作用、修改文件、发送数据、执行远端动作的请求都要可审计、可拒绝、可追踪。</p></div><div class="toolbar"><button onclick="switchView(\'monitor\')">先检查能力</button><button class="danger" onclick="toggleSafeMode()">暂停写动作</button></div></div>';html+='<div class="panel"><div class="panelHead"><div><h2>待你处理</h2><p>真实队列来自 pending approvals、review tasks、failed/waiting runs。</p></div><span class="badge amber">'+items.length+' pending</span></div><div class="panelBody">';if(!items.length){html+='<div class="empty">暂无待审批或待处理动作。</div>'}else{html+=items.map(renderApprovalCard).join('')}html+='</div></div>';document.getElementById('view-approvals').innerHTML=html}
function renderApprovalCard(item){var risk=String(item.risk||item.status||'medium').toLowerCase();var cls=/fail|destructive|high|blocked/.test(risk)?'riskHigh':/review|waiting|pending|medium/.test(risk)?'riskMedium':'riskLow';var title=item.title||item.id||item.taskId;var meta=[item.kind,item.status,item.issueId,item.taskId].filter(Boolean).join(' · ');var buttons=actionForApproval(item);return '<article class="notice '+cls+'"><div class="split"><div><strong>'+esc(title)+'</strong><p class="mono">'+esc(meta)+' · '+esc(fmt(item.updatedAt))+'</p></div>'+badge(item.status||item.kind)+'</div><div class="split" style="margin-top:10px"><span class="rowSub dangerousHint">执行前请检查影响对象、diff、日志和是否可回滚。</span><div class="actions">'+buttons+'</div></div></article>'}
function actionForApproval(item){if(item.kind==='task'||item.issueId&&item.taskId){return '<button onclick="openTask(\''+esc(item.issueId)+'\',\''+esc(item.taskId)+'\')">审查</button><button class="success mutating" onclick="verifyTask(\''+esc(item.issueId)+'\',\''+esc(item.taskId)+'\')">记录验证</button><button class="primary mutating" onclick="acceptTask(\''+esc(item.issueId)+'\',\''+esc(item.taskId)+'\')">验收</button>'}if(item.kind==='run'||item.runId){return '<button onclick="openRun(\''+esc(item.id||item.runId)+'\')">查看运行</button><button class="danger mutating" onclick="cancelRun(\''+esc(item.id||item.runId)+'\')">取消</button>'}if(item.kind==='local-job')return '<button onclick="openLocalJob(\''+esc(item.id)+'\')">查看 Job</button><button class="danger mutating" onclick="cancelLocalJob(\''+esc(item.id)+'\')">取消</button>';return '<button onclick="switchView(\'evidence\')">查看证据</button>'}
function renderWorkbench(){var issues=activeIssues();var current=arr(obj(state.board).issues).find(function(i){return i.id===obj(state.projectState).currentIssueId})||issues[0];var runtime=obj(state.runtime);var repoRows=[['Root',state.repoRoot],['Registered',runtime.registered?'yes':'no'],['Repo ID',runtime.repoId],['Checkout',runtime.checkoutId],['Daemon',obj(runtime.daemon).status],['Projection',obj(runtime.projection).generatedAt||'—']];var html='<div class="pageHead"><div><h1>Git 仓库工作台</h1><p>把仓库状态、Issue/Task、Run、Direct Edit 和检查入口放在同一上下文里。</p></div><div class="toolbar"><button onclick="switchView(\'tasks\')">执行详情</button></div></div>';html+='<div class="grid layout2"><div class="panel"><div class="panelHead"><div><h2>Focused Repository</h2><p>当前 Local Bridge 绑定的物理仓库。</p></div>'+badge(runtime.registered?'registered':'unregistered')+'</div><div class="panelBody"><dl class="detailGrid">'+repoRows.map(function(x){return '<dt>'+esc(x[0])+'</dt><dd class="mono">'+esc(x[1]||'—')+'</dd>'}).join('')+'</dl></div></div><div class="panel"><div class="panelHead"><div><h2>当前 Goal</h2><p>执行焦点决定启动任务和集成策略。</p></div></div><div class="panelBody">'+(current?'<div class="rowTitle">'+esc(current.title)+'</div><div class="rowSub mono">'+esc(current.id)+' · '+esc(current.status)+'</div>':'<div class="empty">没有当前 Issue</div>')+'</div></div></div>';html+='<div class="sectionTitle"><h2>Issue / Task</h2><span class="badge">'+issues.length+' issues</span></div>';html+=issues.slice(0,8).map(renderIssueCard).join('')||'<div class="empty">暂无 Issue</div>';document.getElementById('view-workbench').innerHTML=html}
function renderIssueCard(issue){return '<div class="panel" style="margin-bottom:12px"><div class="panelHead"><div><h2>'+esc(issue.title)+'</h2><p class="mono">'+esc(issue.id)+' · '+esc(issue.status)+' · '+esc(issue.lifecycleStatus||'')+'</p></div><div class="actions"><button class="mutating" onclick="launchIssue(\''+esc(issue.id)+'\')">启动 Issue</button></div></div><div class="panelBody">'+arr(issue.tasks).map(function(task){return '<div class="row"><div><div class="rowTitle">'+esc(task.title)+'</div><div class="rowSub mono">'+esc(task.id)+' · '+esc(task.effectiveStatus||task.status)+'</div></div><div class="actions">'+badge(task.effectiveStatus||task.status)+'<button onclick="openTask(\''+esc(issue.id)+'\',\''+esc(task.id)+'\')">详情</button><button class="primary mutating" onclick="launchTask(\''+esc(issue.id)+'\',\''+esc(task.id)+'\')">运行</button></div></div>'}).join('')+'</div></div>'}
function renderTasks(){var q=decisionQueues();var html='<div class="pageHead"><div><h1>任务执行实时详情</h1><p>面向 agent/run 的追踪视图：阶段、日志、diff、事件、取消/重试都在这里。</p></div><div class="toolbar"><button onclick="switchView(\'approvals\')">查看阻塞点</button></div></div>';html+='<div class="grid layout2"><div class="panel"><div class="panelHead"><div><h2>运行中的任务</h2><p>点击追踪会打开流式输出和原始日志。</p></div></div><div class="panelBody">'+renderQueue(arr(q.runningNow),'当前没有运行中的任务')+'</div></div><div class="panel"><div class="panelHead"><div><h2>运行时间线</h2><p>最近 worklog / controller timeline。</p></div></div><div class="panelBody"><div class="timeline">'+renderTimeline(8)+'</div></div></div></div>';html+='<div class="sectionTitle"><h2>Recent Runs</h2><span class="badge">'+arr(state.runs).length+' runs</span></div>'+renderRunGrid();document.getElementById('view-tasks').innerHTML=html}
function renderRunGrid(){var runs=arr(state.runs).slice(0,12);if(!runs.length)return '<div class="empty">暂无 Run</div>';return '<div class="grid layout3">'+runs.map(function(r){var progress=obj(r.progress);var percent=Math.max(0,Math.min(100,Number(progress.percent)||0));return '<div class="card"><div class="split"><strong>'+esc(short(progress.currentActivity||r.runId,70))+'</strong>'+badge(r.status)+'</div><div class="rowSub mono">'+esc(r.issueId||'')+' / '+esc(r.taskId||'')+'</div><div class="progressTrack" style="margin:12px 0"><div class="progressFill" style="width:'+percent+'%"></div></div><div class="split"><span class="rowSub">'+esc(progress.phase||r.agent||'agent')+'</span><button onclick="openRun(\''+esc(r.runId)+'\')">追踪</button></div></div>'}).join('')+'</div>'}
function renderMonitor(){var r=recovery();var summary=obj(r.summary);var caps=arr(r.capabilities);var actions=arr(r.recommendedActions);var html='<div class="pageHead"><div><h1>助手能力监控</h1><p>这里专门回答：为什么工具被挡、哪里能自动恢复、哪里必须人工授权、哪里应该切换沙盒补丁。</p></div><div class="toolbar"><button onclick="refreshRecovery()">重新探测</button><button class="warn mutating" onclick="applyRecovery(\'recovery.probe_again\')">执行只读探测</button></div></div>';html+='<div class="grid metrics">'+metric('Overall',r.overallState||'unknown','能力矩阵','')+metric('Blocked',summary.blocked||caps.filter(function(c){return c.state==='blocked'||c.state==='unavailable'}).length,'不可用能力','')+metric('Degraded',summary.degraded||caps.filter(function(c){return c.state==='degraded'}).length,'退化能力','')+metric('Fallback',r.fallbackRequired?'YES':'NO','平台拦截切换','')+metric('Actions',actions.length,'建议动作','')+'</div>';html+='<div class="grid layout2"><div class="panel"><div class="panelHead"><div><h2>能力矩阵</h2><p>每项能力都要有状态、归因、证据和下一步，而不是笼统地显示失败。</p></div>'+badge(r.overallState||'unknown')+'</div><div class="panelBody">'+(caps.map(renderCapability).join('')||'<div class="empty">暂无 capability 数据</div>')+'</div></div>';html+='<div class="panel"><div class="panelHead"><div><h2>恢复动作</h2><p>高风险动作需要明确确认；platform_blocked 不会建议重启死循环。</p></div></div><div class="panelBody">'+(actions.map(renderRecoveryAction).join('')||'<div class="empty">当前无推荐恢复动作</div>')+'</div></div></div>';if(arr(r.notes).length)html+='<div class="panel" style="margin-top:16px"><div class="panelHead"><div><h2>诊断说明</h2><p>用于解释平台侧限制、本地故障和安全边界。</p></div></div><div class="panelBody">'+arr(r.notes).map(function(n){return '<div class="notice brand"><strong>说明</strong><p>'+esc(n)+'</p></div>'}).join('')+'</div></div>';document.getElementById('view-monitor').innerHTML=html}
function renderCapability(c){var ev=arr(c.evidence)[0];return '<div class="notice '+statusClass(c.state)+'"><div class="split"><strong>'+esc(c.label||c.id)+'</strong>'+badge(c.state)+'</div><p>'+esc(c.class||'unknown')+' · '+esc(c.reason||'')+'</p>'+(ev?'<p class="mono faint">'+esc(ev.source||'evidence')+' · '+esc(fmt(ev.at))+'</p>':'')+'</div>'}
function renderRecoveryAction(a){return '<div class="notice '+statusClass(a.risk)+'"><div class="split"><strong>'+esc(a.title||a.id)+'</strong>'+badge(a.risk)+'</div><p>'+esc(a.description||'')+'</p><p class="mono faint">confirmation: '+esc(a.confirmation)+' · class: '+esc(a.class)+'</p><div class="actions" style="margin-top:9px"><button class="mutating" onclick="applyRecovery(\''+esc(a.id)+'\')">执行恢复动作</button></div></div>'}
function renderPlugins(){var html='<div class="pageHead"><div><h1>能力与插件中心</h1><p>插件不是简单开关，而是感知/执行能力、风险等级、授权状态和审批策略。</p></div><div class="toolbar"><button onclick="refresh()">刷新状态</button></div></div>';var list=plugins();html+='<div class="grid layout3">'+(list.map(function(p){var actions=arr(p.actions);var health=obj(p.health);var lifecycle=obj(p.lifecycle);var error=arr(health.errors)[0]||lifecycle.reason||'';return '<div class="card"><div class="split"><div><strong>'+esc(p.displayName||p.pluginId)+'</strong><div class="rowSub mono">'+esc(p.pluginId)+' · '+esc(p.provider||'provider')+'</div></div>'+badge(health.state||lifecycle.state||'unknown')+'</div><p class="muted">'+esc(error||'插件状态正常，动作会按风险策略进入审批或执行。')+'</p><div class="sectionTitle"><h2>Actions</h2><span class="badge">'+actions.length+'</span></div>'+actions.slice(0,6).map(function(a){return '<div class="split" style="margin-bottom:7px"><span>'+esc(a.title||a.actionId)+'</span>'+badge(a.risk||'readonly')+'</div>'}).join('')+'</div>'}).join('')||'<div class="empty">暂无插件</div>')+'</div>';document.getElementById('view-plugins').innerHTML=html}
function renderAutomations(){var list=routines();var html='<div class="pageHead"><div><h1>自动化任务</h1><p>自动化可以自主运行，但所有写动作仍经 Approval Inbox 或插件确认策略。</p></div><div class="toolbar"><button onclick="switchView(\'approvals\')">审批中心</button></div></div>';html+='<div class="panel"><div class="panelHead"><div><h2>Routines</h2><p>来自 personal assistant runtime 的例行任务。</p></div><span class="badge">'+list.length+' routines</span></div><div class="panelBody">'+(list.map(function(r){return '<div class="row"><div><div class="rowTitle">'+esc(r.title||r.name||r.routineId)+'</div><div class="rowSub">'+esc(r.schedule||r.trigger||r.description||'')+'</div></div><div class="actions">'+badge(r.status||r.enabled)+'<button class="mutating" onclick="runRoutine(\''+esc(r.routineId||r.id)+'\')">立即运行</button></div></div>'}).join('')||'<div class="empty">暂无自动化 routine</div>')+'</div></div>';html+='<div class="sectionTitle"><h2>Assistant Inbox</h2><span class="badge">'+inbox().length+' items</span></div>'+renderInbox();document.getElementById('view-automations').innerHTML=html}
function renderInbox(){var items=inbox().slice(0,10);if(!items.length)return '<div class="empty">暂无助手收件箱消息</div>';return '<div class="grid layout2">'+items.map(function(item){return '<div class="card"><div class="split"><strong>'+esc(item.title||item.itemId)+'</strong>'+badge(item.status||'unread')+'</div><p class="muted">'+esc(item.summary||item.body||item.message||'')+'</p><div class="actions"><button class="mutating" onclick="updateInbox(\''+esc(item.itemId||item.id)+'\',\'read\')">标记已读</button><button class="mutating" onclick="updateInbox(\''+esc(item.itemId||item.id)+'\',\'archived\')">归档</button></div></div>'}).join('')+'</div>'}
function renderEvidence(){var html='<div class="pageHead"><div><h1>执行凭证与报告</h1><p>所有运行、检查、浏览器动作、补丁交接和恢复动作都应该能回看证据链。</p></div><div class="toolbar"><button class="mutating" onclick="exportWorklog()">导出 Worklog</button></div></div>';html+='<div class="grid layout2"><div class="panel"><div class="panelHead"><div><h2>Controller Timeline</h2><p>最近事件流。</p></div></div><div class="panelBody"><div class="timeline">'+renderTimeline(30)+'</div></div></div><div class="panel"><div class="panelHead"><div><h2>Recovery Audit</h2><p>恢复动作会写 audit evidence。</p></div></div><div class="panelBody">'+renderRecoveryAuditHint()+'</div></div></div>';document.getElementById('view-evidence').innerHTML=html}
function renderTimeline(limit){var tl=arr(obj(state.timeline).events||state.timeline).slice(0,limit||20);if(!tl.length)return '<div class="empty">暂无 timeline 事件</div>';return tl.map(function(e){return '<div class="timelineItem"><div class="split"><strong>'+esc(e.title||e.message||e.type||e.category||'event')+'</strong><span class="faint mono">'+esc(fmt(e.at||e.createdAt||e.updatedAt))+'</span></div><p class="muted">'+esc(short(e.summary||e.detail||e.description||e.id||'',140))+'</p></div>'}).join('')}
function renderRecoveryAuditHint(){var r=recovery();return '<div class="notice brand"><strong>证据原则</strong><p>恢复动作必须记录 actionId、risk、confirmation、affectedPaths 和 evidence。当前推荐动作：'+esc(arr(r.recommendedActions).map(function(a){return a.id}).join(', ')||'无')+'</p></div>'}
function refreshRecovery(){api('/api/recovery/probe').then(function(r){state.recovery=r;renderAll();toastMsg('能力探测完成')}).catch(function(e){toastMsg(e.message)})}
function applyRecovery(id){if(!requireWrite())return;if(!confirm('确认执行恢复动作 '+id+'？高风险动作可能重启或清理本地 repo-harness 运行态。'))return;api('/api/recovery/apply',{method:'POST',body:JSON.stringify({actionId:id,confirmAuthorization:true,authorization:id,reason:'local GUI assistant monitor action'})}).then(function(){toastMsg('恢复动作已提交');refresh()}).catch(function(e){toastMsg(e.message)})}
function runRoutine(id){if(!requireWrite())return;api('/api/assistant/routines/'+encodeURIComponent(id)+'/run',{method:'POST',body:'{}'}).then(function(){toastMsg('Routine 已运行');refresh()}).catch(function(e){toastMsg(e.message)})}
