function stringValue(v){if(v==null)return '';if(typeof v==='string')return v;if(Array.isArray(v))return v.map(stringValue).join(' ');try{return JSON.stringify(v,null,2)}catch(_e){return String(v)}}
function parseAgentOutput(log){var entries=[];String(log||'').split(/\r?\n/).forEach(function(line){if(!line.trim())return;var payload;try{payload=JSON.parse(line)}catch(_e){entries.push({kind:'output',title:'输出',detail:line});return}var item=payload.item&&typeof payload.item==='object'?payload.item:payload;var type=String(item.type||payload.type||payload.event||'').toLowerCase();var entry=null;if(type.includes('command')){entry={kind:'command',title:stringValue(item.command||item.cmd||payload.command||'执行命令'),detail:stringValue(item.aggregated_output||item.output||item.result||''),meta:stringValue(item.status||item.exit_code||'命令')}}else if(/file|patch|edit|change/.test(type)){entry={kind:'change',title:'修改 '+stringValue(item.path||item.file_path||item.filename||'项目文件'),detail:stringValue(item.changes||item.diff||item.patch||''),meta:'文件变更'}}else if(/error|failed/.test(type)||payload.error){entry={kind:'error',title:'执行异常',detail:stringValue(payload.error&&payload.error.message||payload.error||payload.message||line),meta:'error'}}else if(/message|reasoning|analysis/.test(type)){entry={kind:'message',title:'Agent 消息',detail:stringValue(item.text||item.content||payload.message||''),meta:'message'}}if(entry&&(entry.title||entry.detail)){var previous=entries[entries.length-1];if(!previous||previous.kind!==entry.kind||previous.title!==entry.title||previous.detail!==entry.detail)entries.push(entry)}});return entries.slice(-220)}
function eventAgentOutput(events){return arr(events).filter(function(event){return !['run_heartbeat','log_updated'].includes(event.type)}).map(function(event){var data=obj(event.data);var kind=data.command?'command':data.path||data.changedPaths?'change':/failed|cancelled/.test(event.type)?'error':/succeeded|integrated|verified/.test(event.type)?'success':'status';return{kind:kind,title:event.message||event.type,detail:stringValue(data.command||data.path||data.changedPaths||data.error||''),meta:fmt(event.at)}}).slice(-120)}
function runIcon(kind){return({command:'›_',change:'Δ',message:'A',analysis:'◇',error:'!',success:'✓',status:'•',output:'↳'})[kind]||'•'}
